<?php
declare(strict_types=1);
require_once dirname(__DIR__,2).'/includes/contenido.php';
$token=strtolower(trim((string)($_GET['token']??'')));$certificado=null;if(preg_match('/^[a-f0-9]{64}$/',$token)){$q=obtenerConexion()->prepare("SELECT c.numero,c.emitido_at,c.finalizado_at,c.estado,a.nombre capacitacion,a.duracion,CONCAT(u.nombre,' ',u.apellido) estudiante FROM certificados_capacitacion c JOIN asignaturas a ON a.id=c.asignatura_id JOIN usuarios u ON u.id=c.estudiante_id WHERE c.token_verificacion=:t LIMIT 1");$q->execute(['t'=>$token]);$certificado=$q->fetch()?:null;}if(!$certificado)http_response_code(404);$pageTitle=$certificado?'Certificado verificado | Atenea':'Certificado no encontrado | Atenea';$pageDescription='Verificación pública de certificados académicos de Atenea.';$pageClass='certificate-verification-page';require dirname(__DIR__,2).'/includes/header.php';
?>
<main class="main"><section class="section"><div class="container py-5"><div class="mx-auto border rounded shadow-sm p-4 p-md-5 text-center" style="max-width:760px"><?php if(!$certificado):?><div class="display-1 fw-bold text-danger">404</div><h1 class="h2">Certificado no encontrado</h1><p>El código es inválido o el certificado ya no está disponible.</p><?php else:?><i class="bi bi-patch-check-fill display-2 <?=$certificado['estado']==='emitido'?'text-success':'text-danger'?>"></i><h1 class="h2 mt-3"><?=$certificado['estado']==='emitido'?'Certificado válido':'Certificado revocado'?></h1><p class="lead mb-4">Atenea confirma que <strong><?=atenea_e($certificado['estudiante'])?></strong> finalizó la capacitación <strong><?=atenea_e($certificado['capacitacion'])?></strong>.</p><dl class="row text-start mb-0"><dt class="col-sm-5">Número</dt><dd class="col-sm-7"><?=atenea_e($certificado['numero'])?></dd><dt class="col-sm-5">Fecha de finalización</dt><dd class="col-sm-7"><?=atenea_e($certificado['finalizado_at'])?></dd><?php if($certificado['duracion']):?><dt class="col-sm-5">Duración</dt><dd class="col-sm-7"><?=atenea_e($certificado['duracion'])?></dd><?php endif;?><dt class="col-sm-5">Estado</dt><dd class="col-sm-7"><?=atenea_e(ucfirst($certificado['estado']))?></dd></dl><?php endif;?><a class="btn-atenea mt-4" href="<?=atenea_url('index.php')?>">Volver a Atenea</a></div></div></section></main>
